  it("renders placeholder cards when cards is undefined", () => {
    render(<TrendingStrip />)
    expect(screen.getByRole("region", { name: "Trending cards" })).toBeInTheDocument()
    // Should render all placeholder cards
    for (const card of TRENDING_PLACEHOLDER) {
      expect(screen.getByText(card.name)).toBeInTheDocument()
    }
  })

  it("renders placeholder cards when cards is empty array", () => {
    render(<TrendingStrip cards={[]} />)
    expect(screen.getByRole("region", { name: "Trending cards" })).toBeInTheDocument()
    expect(screen.getByText(TRENDING_PLACEHOLDER[0].name)).toBeInTheDocument()
  })

  it("renders provided cards instead of placeholder when cards are given", () => {
    render(<TrendingStrip cards={mockCards} />)
    expect(screen.getByText("Ragavan, Nimble Pilferer")).toBeInTheDocument()
    expect(screen.getByText("Charizard ex")).toBeInTheDocument()
